+        let ptr = cell.get();
+        if ptr.is_null() {
+            let p = unsafe { TOUPPER_TABLE.as_ptr().add(128) };
+            cell.set(p);
+        }
+        cell.as_ptr() as *const *const i32
+    })
+}
+
